Object.assign = null
import Starling from '../../src/index'
import { EN_TXT_CDN_frontend } from '../data/remote-demo-en'
import ax from 'axios'
async function waitInSec(timeInSec = 1) {
  await new Promise(resolve => {
    setTimeout(resolve, 1000 * timeInSec)
  })
}

const request = jest.fn()
const memoryStore = {
  _data: {},
  get(key) {
    return this._data[key]
  },
  set(key, value) {
    this._data[key] = value
  },
  del(key) {
    delete this._data[key]
  },
  clear() {
    this._data = {}
  }
} // 实现get/set方法的内存存储对象
const baseOptions = {
  apiKey: '878eda30470811ed9131ebf81a95d42f',
  locale: 'en',
  namespace: 'op_test',
  cdn: 'https://lf-starling.zijiecdn.cn/obj/starling-web-dist/starling',
  timeout: 5000,
  tracker: () => {},
  request: request,
  store: memoryStore
}
const textKey = `text.${baseOptions.apiKey}.${baseOptions.namespace}.${baseOptions.locale}`
const versionKey = `version.${baseOptions.apiKey}.${baseOptions.namespace}.${baseOptions.locale}`

describe('集成测试 - CDN模式下store存储验证', () => {
  test('cdn模式下默认文案应存储在store中', async () => {
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
      }
    })
    memoryStore.clear()
    const starling = new Starling({ ...baseOptions, store: memoryStore }) // 传递符合接口的store
    // 加载前检查store为空
    expect(memoryStore._data).toEqual({})
    const fetchedData = await starling.load()
    // console.log('memoryStore=',memoryStore)
    expect(fetchedData).toEqual(EN_TXT_CDN_frontend)
    expect(memoryStore.get(textKey)).toEqual(EN_TXT_CDN_frontend)

    // const { equalNs, diffNs } = await Starling._textManager._checkVersions(namespaces)

    // 假设实例通过属性存储版本和语言，需根据实际实现调整
    expect(memoryStore.get(versionKey)).toBe('1')
  })

  test('cdn模式下，如果设置cache为false文案不应存储在store中', async () => {
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
      }
    })
    memoryStore.clear()
    const starling = new Starling({ ...baseOptions, store: memoryStore, cache: false }) // 传递符合接口的store
    // 加载前检查store为空
    expect(memoryStore._data).toEqual({})
    const fetchedData = await starling.load()
    expect(fetchedData).toEqual(EN_TXT_CDN_frontend)
    expect(memoryStore.get(textKey)).toBeUndefined()
    expect(memoryStore.get(versionKey)).toBeUndefined()
  })

  test('lazyUpdate=true时，如果本地存储有数据，load先返回本地存储并异步更新', async () => {
    request.mockImplementationOnce(() =>
      Promise.resolve({
        data: {
          status: 200,
          message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
        }
      })
    )

    memoryStore.clear()
    const localCache = { ...EN_TXT_CDN_frontend, localCacheKey: 111111 }
    memoryStore.set(textKey, localCache)
    const starling = new Starling({ ...baseOptions, lazyUpdate: true })
    // 首次加载填充本地存储
    // @ts-ignore
    const localTexts = await starling.load()
    // 先返回本地缓存
    expect(localTexts).toEqual(localCache)
    await waitInSec()
    // 再更新本地缓存
    expect(memoryStore.get(textKey)).toEqual(EN_TXT_CDN_frontend)
    console.log('version:', memoryStore.get(versionKey))
  })

  test('lazyUpdate=false时，load应等待请求返回', async () => {
    memoryStore.clear()
    const mockRequest = jest.fn(() =>
      Promise.resolve({
        data: {
          status: 200,
          message: {
            Version: '2',
            Lang: 'en',
            Data: { ...EN_TXT_CDN_frontend, updated: true },
            Updated: true
          }
        }
      })
    )
    const starling = new Starling({ ...baseOptions, lazyUpdate: false, request: mockRequest })
    const loadPromise = starling.load()
    // 验证请求已发送但未完成时load仍在等待
    // expect(mockRequest).toHaveBeenCalled()
    const texts = await loadPromise

    // 验证返回的是最新数据
    expect(texts).toEqual({ ...EN_TXT_CDN_frontend, updated: true })
  })

  test('普通cdn,真实请求', async () => {
    memoryStore.clear()
    let starling = new Starling({ ...baseOptions, request: ax })
    let r = await starling.load()
    // console.log('r=',r)
    let cacheText = memoryStore.get(textKey)
    const cacheVersion = memoryStore.get(versionKey)
    // console.log('cacheText=',cacheText)
    // console.log('cacheVersion=',cacheVersion)
    expect(r).toEqual(cacheText)
    // memoryStore.clear()
    // starling = new Starling({ ...baseOptions, request: ax, cache: false })
    // r = await starling.load()
    // cacheText = memoryStore.get(textKey)
    // console.log('cacheText=',cacheText)
  })

  test('普通cdn,真实请求,多次请求会更新本地存储', async () => {
    memoryStore.clear()
    let starling = new Starling({ ...baseOptions, request: ax })
    let r = await starling.load()
    let cacheText = memoryStore.get(textKey)
    expect(r).toEqual(cacheText)
    memoryStore.set(textKey, { ...cacheText, newKey: 'value' })
    cacheText = memoryStore.get(textKey)
    // 不一样了
    expect(Object.keys(cacheText).length).toBeGreaterThan(Object.keys(r).length)
    await starling.load()
    cacheText = memoryStore.get(textKey)
    // 又一样了
    expect(r).toEqual(cacheText)
  })

  test('普通cdn,真实请求,删除version 不影响拉取', async () => {
    memoryStore.clear()
    let starling = new Starling({ ...baseOptions, request: ax })
    let r = await starling.load()
    let cacheText = memoryStore.get(textKey)
    expect(r).toEqual(cacheText)
    let versionCache = memoryStore.get(versionKey)
    expect(versionCache).toBeTruthy()
    memoryStore.del(versionKey)
    versionCache = memoryStore.get(versionKey)
    expect(versionCache).toBeUndefined()
    r = await starling.load()
    cacheText = memoryStore.get(textKey)
    // 不影响拉取
    expect(r).toEqual(cacheText)
  })

  test('普通cdn,真实请求,该写 version不影响拉取', async () => {
    memoryStore.clear()
    let starling = new Starling({ ...baseOptions, request: ax })
    let r = await starling.load()
    let cacheText = memoryStore.get(textKey)
    expect(r).toEqual(cacheText)
    let versionCache = memoryStore.get(versionKey)
    expect(versionCache).toBeTruthy()
    memoryStore.set(versionKey, '123')
    versionCache = memoryStore.get(versionKey)
    expect(versionCache).toBe('123')
    r = await starling.load()
    cacheText = memoryStore.get(textKey)
    // 不影响拉取
    expect(r).toEqual(cacheText)
  })

  test('非cdn,正常', async () => {
    request.mockImplementationOnce(() =>
      Promise.resolve({
        data: {
          status: 200,
          message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
        }
      })
    )
    const { cdn, ...noCdnOptions } = baseOptions
    memoryStore.clear()
    let starling = new Starling({ ...noCdnOptions, zoneHost: '11' })
    let r = await starling.load()
    // 拉取结果正常
    expect(r).toEqual(EN_TXT_CDN_frontend)
    let cacheText = memoryStore.get(textKey)
    // 缓存正常
    expect(cacheText).toBe(EN_TXT_CDN_frontend)
    memoryStore.clear()
    starling = new Starling({ ...noCdnOptions, zoneHost: '11', cache: false })
    request.mockImplementationOnce(() =>
      Promise.resolve({
        data: {
          status: 200,
          message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
        }
      })
    )
    r = await starling.load()
    expect(r).toEqual(EN_TXT_CDN_frontend)
    cacheText = memoryStore.get(textKey)
    expect(cacheText).toBeUndefined()
    let cacheVersion = memoryStore.get(versionKey)
    expect(cacheVersion).toBeUndefined()
  })
})
